const lib = global.get('lib');
if (!lib || !lib.telemetry || typeof lib.telemetry.resolveTelemetryTemplate !== 'function') {
  node.status({ fill: 'red', shape: 'ring', text: 'template API missing' });
  return { payload: { error: 'TEMPLATE_API_MISSING' } };
}

const telemetry = lib.telemetry;

// Update this mapping as new product lines come online.
const equipmentToProfile = {
  PCS: 'Delta_280_ss40k',
  PCS2: 'Delta_280_ss40k',
  PCS3: 'Delta_280_ss40k',
  PCS4: 'Delta_280_ss40k',
  MBMU: 'MBMU_280_ss40k',
  Meter: 'eGauge_280_ss40k',
  Meter2: 'eGauge_280_ss40k'
};

const modelIndexMap = {
  '40100': '0',
  '40101': '1',
  '40102': '2',
  '40103': '3',
  '40104': '4'
};

const templateCache = {};
const lookup = {};

for (const [equipment, profileName] of Object.entries(equipmentToProfile)) {
  let template;
  if (templateCache[profileName]) {
    template = templateCache[profileName];
  } else {
    template = telemetry.resolveTelemetryTemplate(profileName);
    templateCache[profileName] = template;
  }

  const telemetryEntries = Array.isArray(template.telemetry) ? template.telemetry : [];
  for (const entry of telemetryEntries) {
    if (!entry || !entry.id || !entry.ss40k || !entry.ss40k.name || !entry.ss40k.model) continue;
    lookup[`${equipment}.${entry.id}`] = {
      equipment,
      sourceTagID: `${equipment}.${entry.id}`,
      profileName,
      name: entry.ss40k.name,
      model: String(entry.ss40k.model),
      modelIndex: modelIndexMap[String(entry.ss40k.model)] || '0'
    };
  }
}

global.set('ss40kLookup', lookup);
global.set('ss40kEquipmentToProfile', equipmentToProfile);
global.set('ss40kModelIndexMap', modelIndexMap);

node.status({ fill: 'green', shape: 'dot', text: `${Object.keys(lookup).length} mapped tags` });
msg.payload = {
  lookupCount: Object.keys(lookup).length,
  equipmentToProfile,
  modelIndexMap,
  sample: Object.fromEntries(Object.entries(lookup).slice(0, 10))
};
return msg;

const lookup = global.get('ss40kLookup') || {};
const newTelemetry = global.get('NEW_telemetry') || {};
if (!Object.keys(lookup).length) {
  node.status({ fill: 'yellow', shape: 'ring', text: 'lookup missing' });
  return [null, { payload: { error: 'SS40K_LOOKUP_MISSING' } }, null];
}

const groups = {};

for (const [equipment, samples] of Object.entries(newTelemetry)) {
  if (!Array.isArray(samples)) continue;
  for (const sample of samples) {
    if (!sample || !sample.tagID) continue;
    const meta = lookup[sample.tagID];
    if (!meta) continue;

    const groupKey = `${meta.equipment}::${meta.model}`;
    if (!groups[groupKey]) {
      groups[groupKey] = {
        equipment: meta.equipment,
        model: meta.model,
        modelIndex: meta.modelIndex,
        version: '2.0',
        latestTimestamp: null,
        fixed: {}
      };
    }

    groups[groupKey].fixed[meta.name] = sample.value;

    if (sample.timestamp) {
      const iso = typeof sample.timestamp === 'string' ? sample.timestamp : new Date(sample.timestamp).toISOString();
      if (!groups[groupKey].latestTimestamp || iso > groups[groupKey].latestTimestamp) {
        groups[groupKey].latestTimestamp = iso;
      }
    }
  }
}

const messages = Object.values(groups)
  .sort((a, b) => `${a.equipment}.${a.model}`.localeCompare(`${b.equipment}.${b.model}`))
  .map((group) => {
    const payload = {
      [group.modelIndex]: {
        fixed: group.fixed,
        id: Number(group.model),
        version: group.version
      }
    };

    return {
      topic: `fort/v1/things/CHANGE_ME_GSN/telem`,
      payload,
      ss40k: {
        equipment: group.equipment,
        model: group.model,
        modelIndex: group.modelIndex,
        timestamp: group.latestTimestamp,
        pointCount: Object.keys(group.fixed).length
      }
    };
  });

node.status({ fill: 'green', shape: 'dot', text: `${messages.length} payloads` });
return [messages, null, { payload: messages.map((msg) => msg.ss40k) }];

msg.payload = {
  equipmentToProfile: global.get('ss40kEquipmentToProfile') || {},
  modelIndexMap: global.get('ss40kModelIndexMap') || {},
  lookup: global.get('ss40kLookup') || {}
};
return msg;
